<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Maze Bots</title>
<style>
  :root { --bg:#0d1117; --panel:#161b22; --ink:#e6edf3; --accent:#58a6ff; }
  * { box-sizing:border-box; }
  body {
    margin:0; background:var(--bg); color:var(--ink);
    font-family:"Segoe UI",system-ui,sans-serif;
    display:flex; flex-direction:column; align-items:center;
    min-height:100vh; padding:24px;
  }
  h1 { font-size:20px; font-weight:600; margin:0 0 16px; letter-spacing:.3px; }
  #hud {
    display:flex; gap:14px; align-items:center; margin-bottom:16px; flex-wrap:wrap;
    justify-content:center;
  }
  .stat {
    background:var(--panel); border:1px solid #30363d; border-radius:10px;
    padding:10px 16px; min-width:120px; text-align:center;
  }
  .stat .label { font-size:11px; text-transform:uppercase; letter-spacing:1px; color:#8b949e; }
  .stat .value { font-size:22px; font-weight:700; margin-top:2px; font-variant-numeric:tabular-nums; }
  #completed .value { color:var(--accent); }
  #reset {
    background:var(--accent); color:#07101f; border:none; border-radius:10px;
    padding:12px 20px; font-size:14px; font-weight:700; cursor:pointer;
    transition:transform .08s ease, filter .15s ease;
  }
  #reset:hover { filter:brightness(1.08); }
  #reset:active { transform:scale(.96); }
  #maze {
    background:#010409; border-radius:12px; border:1px solid #30363d;
    box-shadow:0 10px 40px rgba(0,0,0,.5);
  }
  .hint { color:#8b949e; font-size:12px; margin-top:14px; }
</style>
</head>
<body>
  <h1>🤖 Maze Bots — 24 autonomous pathfinders</h1>
  <div id="hud">
    <div id="completed" class="stat"><div class="label">Completed</div><div class="value">0 / 24</div></div>
    <div id="timer" class="stat"><div class="label">Time</div><div class="value">0.0s</div></div>
    <button id="reset">Reset</button>
  </div>
  <canvas id="maze" width="504" height="504"></canvas>
  <div class="hint">Bots BFS to the green exit. Try <code>game.tick(5000)</code> in the console.</div>

<script>
(function () {
  "use strict";

  // ---- config ----
  const COLS = 21, ROWS = 21;      // >= 15x15
  const CELL = 24;                 // 21*24 = 504px  (>= 400)
  const NUM_BOTS = 24;
  const MS_PER_STEP = 100;         // sim time per discrete step
  const N = 0, E = 1, S = 2, W = 3;
  const DX = [0, 1, 0, -1], DY = [-1, 0, 1, 0], OPP = [S, W, N, E];

  const canvas = document.getElementById("maze");
  const ctx = canvas.getContext("2d");
  canvas.width = COLS * CELL;
  canvas.height = ROWS * CELL;

  const elCompleted = document.querySelector("#completed .value");
  const elTimer = document.querySelector("#timer .value");

  // ---- state ----
  let grid, path, bots, stepCount, completed, spawn, exit;

  function makeGrid() {
    const g = [];
    for (let r = 0; r < ROWS; r++) {
      const row = [];
      for (let c = 0; c < COLS; c++) row.push({ walls: [true, true, true, true], visited: false });
      g.push(row);
    }
    return g;
  }

  // iterative DFS -> perfect maze (guaranteed solvable)
  function generateMaze() {
    grid = makeGrid();
    const stack = [[0, 0]];
    grid[0][0].visited = true;
    while (stack.length) {
      const [c, r] = stack[stack.length - 1];
      const opts = [];
      for (let d = 0; d < 4; d++) {
        const nc = c + DX[d], nr = r + DY[d];
        if (nc >= 0 && nc < COLS && nr >= 0 && nr < ROWS && !grid[nr][nc].visited) opts.push(d);
      }
      if (opts.length === 0) { stack.pop(); continue; }
      const d = opts[(Math.random() * opts.length) | 0];
      const nc = c + DX[d], nr = r + DY[d];
      grid[r][c].walls[d] = false;
      grid[nr][nc].walls[OPP[d]] = false;
      grid[nr][nc].visited = true;
      stack.push([nc, nr]);
    }
  }

  // BFS shortest path spawn -> exit through open passages
  function solve() {
    const key = (x, y) => y * COLS + x;
    const prev = new Array(COLS * ROWS).fill(-1);
    const seen = new Array(COLS * ROWS).fill(false);
    const q = [spawn];
    seen[key(spawn.x, spawn.y)] = true;
    while (q.length) {
      const cur = q.shift();
      if (cur.x === exit.x && cur.y === exit.y) break;
      const cell = grid[cur.y][cur.x];
      for (let d = 0; d < 4; d++) {
        if (cell.walls[d]) continue;
        const nx = cur.x + DX[d], ny = cur.y + DY[d];
        if (nx < 0 || nx >= COLS || ny < 0 || ny >= ROWS) continue;
        if (seen[key(nx, ny)]) continue;
        seen[key(nx, ny)] = true;
        prev[key(nx, ny)] = key(cur.x, cur.y);
        q.push({ x: nx, y: ny });
      }
    }
    const out = [];
    let k = key(exit.x, exit.y);
    while (k !== -1) { out.unshift({ x: k % COLS, y: (k / COLS) | 0 }); k = prev[k]; }
    return out;
  }

  function cx(x) { return x * CELL + CELL / 2; }
  function cy(y) { return y * CELL + CELL / 2; }

  function spawnBots() {
    bots = [];
    for (let i = 0; i < NUM_BOTS; i++) {
      const jx = ((i % 5) - 2) * 3.0;               // deterministic per-bot jitter
      const jy = (((i / 5) | 0) - 2) * 3.0;
      bots.push({
        x: spawn.x, y: spawn.y,
        pathIndex: 0,
        startDelay: i * 2,                           // stagger so they aren't one blob
        done: false,
        jx, jy,
        hue: (i * 15) % 360,
        dispX: cx(spawn.x), dispY: cy(spawn.y)
      });
    }
  }

  function init() {
    generateMaze();
    spawn = { x: 0, y: 0 };
    exit = { x: COLS - 1, y: ROWS - 1 };
    path = solve();
    spawnBots();
    stepCount = 0;
    completed = 0;
  }

  // ---- simulation: one discrete step advances every eligible bot one cell ----
  function stepOnce() {
    stepCount++;
    for (const b of bots) {
      if (b.done) continue;
      if (stepCount <= b.startDelay) continue;
      if (b.pathIndex < path.length - 1) {
        b.pathIndex++;
        const p = path[b.pathIndex];
        b.x = p.x; b.y = p.y;
      }
      if (b.pathIndex >= path.length - 1) {
        b.done = true;
        completed++;
      }
    }
  }

  function allDone() { return completed >= NUM_BOTS; }

  // ---- rendering ----
  function render() {
    ctx.fillStyle = "#010409";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // exit cell highlight
    ctx.fillStyle = "rgba(63,185,80,.28)";
    ctx.fillRect(exit.x * CELL, exit.y * CELL, CELL, CELL);
    // spawn cell highlight
    ctx.fillStyle = "rgba(88,166,255,.20)";
    ctx.fillRect(spawn.x * CELL, spawn.y * CELL, CELL, CELL);

    // walls
    ctx.strokeStyle = "#5b6673";
    ctx.lineWidth = 2;
    ctx.lineCap = "round";
    ctx.beginPath();
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const w = grid[r][c].walls, x0 = c * CELL, y0 = r * CELL, x1 = x0 + CELL, y1 = y0 + CELL;
        if (w[N]) { ctx.moveTo(x0, y0); ctx.lineTo(x1, y0); }
        if (w[W]) { ctx.moveTo(x0, y0); ctx.lineTo(x0, y1); }
        if (w[E]) { ctx.moveTo(x1, y0); ctx.lineTo(x1, y1); }
        if (w[S]) { ctx.moveTo(x0, y1); ctx.lineTo(x1, y1); }
      }
    }
    ctx.stroke();

    // bots (smoothly eased toward their target cell)
    for (const b of bots) {
      const tx = cx(b.x) + b.jx, ty = cy(b.y) + b.jy;
      b.dispX += (tx - b.dispX) * 0.25;
      b.dispY += (ty - b.dispY) * 0.25;
      const rad = CELL * 0.24;
      ctx.beginPath();
      ctx.arc(b.dispX, b.dispY, rad, 0, Math.PI * 2);
      ctx.fillStyle = b.done ? "#3fb950" : `hsl(${b.hue},85%,62%)`;
      ctx.fill();
      ctx.lineWidth = 1.5;
      ctx.strokeStyle = "rgba(255,255,255,.55)";
      ctx.stroke();
    }
  }

  function updateHUD() {
    elCompleted.textContent = completed + " / " + NUM_BOTS;
    elTimer.textContent = (stepCount * MS_PER_STEP / 1000).toFixed(1) + "s";
  }

  // ---- animation loop (real time) ----
  let last = null, acc = 0;
  function frame(t) {
    if (last === null) last = t;
    const dt = t - last; last = t;
    if (!allDone()) {
      acc += dt;
      while (acc >= MS_PER_STEP) { acc -= MS_PER_STEP; stepOnce(); }
    }
    render();
    updateHUD();
    requestAnimationFrame(frame);
  }

  // ---- public API ----
  function tick(n) {
    n = Math.max(0, n | 0);
    for (let i = 0; i < n && !allDone(); i++) stepOnce();
    render();
    updateHUD();
  }

  function reset() {
    init();
    last = null; acc = 0;
    render();
    updateHUD();
  }

  document.getElementById("reset").addEventListener("click", reset);

  init();
  updateHUD();
  render();

  window.game = {
    get bots() { return bots; },
    get completed() { return completed; },
    get elapsedMs() { return stepCount * MS_PER_STEP; },
    tick: tick,
    reset: reset
  };

  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
